import{_ as o,o as a,c as t,ai as r}from"./chunks/framework.BIXs0jTs.js";const s="/assets/preface-cover.Balx8Fq4.png",u=JSON.parse('{"title":"附录 C：术语表","description":"","frontmatter":{"title":"附录 C：术语表"},"headers":[],"relativePath":"90-appendix/glossary.md","filePath":"90-appendix/glossary.md","lastUpdated":null}'),l={name:"90-appendix/glossary.md"};function n(d,e,p,C,c,i){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="附录-c-术语表-glossary" tabindex="-1">附录 C　术语表（Glossary） <a class="header-anchor" href="#附录-c-术语表-glossary" aria-label="Permalink to &quot;附录 C　术语表（Glossary）&quot;">​</a></h1><p><img src="'+s+'" alt="附录：术语表与概念解释"></p><h2 id="c-1-claude-code-相关术语" tabindex="-1">C.1 Claude Code 相关术语 <a class="header-anchor" href="#c-1-claude-code-相关术语" aria-label="Permalink to &quot;C.1 Claude Code 相关术语&quot;">​</a></h2><p><strong>Agent (代理)</strong> 在 AI 语境下，指不仅能生成文本，还能通过工具（Tools）与外部环境交互、自主执行任务的智能实体。Claude Code 具有 Agent 的特性。</p><p><strong>Context Window (上下文窗口)</strong> LLM 一次能处理的最大 Token 数量。Claude 3.5 Sonnet 拥有 200k Token 的上下文窗口，这使得它能一次性读取大量代码文件。</p><p><strong>REPL (Read-Eval-Print Loop)</strong> “读取-求值-输出”循环。Claude Code 的交互模式本质上是一个增强版的 REPL，用户输入指令，Claude 执行并返回结果。</p><p><strong>Plan Mode (计划模式)</strong> Claude Code 的一种工作模式。在此模式下，Claude 会先生成详细的执行计划，待用户确认后才开始修改文件。适用于复杂或高风险任务。</p><p><strong>CLAUDE.md</strong> 项目根目录下的特殊配置文件。用于定义项目的上下文、常用命令（Skill）和代码风格规范。Claude 每次启动时都会读取它。</p><h2 id="c-2-skill-相关术语" tabindex="-1">C.2 Skill 相关术语 <a class="header-anchor" href="#c-2-skill-相关术语" aria-label="Permalink to &quot;C.2 Skill 相关术语&quot;">​</a></h2><p><strong>Skill (技能)</strong> Claude Code 可调用的自定义工具。通常封装了 Shell 命令或脚本。定义在 <code>CLAUDE.md</code> 或全局配置中。</p><p><strong>Tool Use (工具调用)</strong> LLM 的一种能力，指模型能够生成特定格式的输出来调用预定义的函数或 API。</p><p><strong>Schema (模式)</strong> 用于描述数据结构的规范（通常是 JSON Schema）。在定义 Skill 时，用于描述参数的类型和格式。</p><h2 id="c-3-mcp-与协议相关术语" tabindex="-1">C.3 MCP 与协议相关术语 <a class="header-anchor" href="#c-3-mcp-与协议相关术语" aria-label="Permalink to &quot;C.3 MCP 与协议相关术语&quot;">​</a></h2><p><strong>MCP (Model Context Protocol)</strong> 一种开放标准协议，旨在标准化 AI 模型与外部数据源（如数据库、API、本地文件）之间的连接方式。</p><p><strong>Host (宿主)</strong> 运行 LLM 的应用程序，如 Claude Desktop App、Claude Code CLI 或 Cursor。Host 负责发起连接请求。</p><p><strong>Server (服务端)</strong> MCP 架构中的数据提供方。它通过标准协议暴露 Resources（资源）、Prompts（提示词）和 Tools（工具）。</p><p><strong>Client (客户端)</strong> MCP 架构中连接 Host 和 Server 的组件。在 Claude Code 中，CLI 本身充当了 Client 的角色。</p><p><strong>Resource (资源)</strong> MCP 中的一种数据类型，代表可读取的数据块（如文件内容、数据库记录）。类似于 HTTP 中的 GET 请求。</p><p><strong>Transport (传输层)</strong> MCP 通信的底层通道。目前主要支持 Stdio（标准输入输出）和 SSE（Server-Sent Events）。</p>',19)])])}const h=o(l,[["render",n]]);export{u as __pageData,h as default};
